uint16_t fft_peak_bin(int16_t* re,uint8_t n,uint8_t* pb){
  static int16_t im[64];
  for(uint8_t i=0;i<n;i++)im[i]=0;
  uint8_t j=0;
  for(uint8_t i=1;i<n-1;i++){
    uint8_t bit=n>>1;
    for(;j&bit;bit>>=1)j^=bit;
    j^=bit;
    if(i<j){int16_t t=re[i];re[i]=re[j];re[j]=t;}}
  for(uint8_t len=2;len<=n;len<<=1)
    for(uint8_t i=0;i<n;i+=len)
      for(uint8_t k=0;k<len/2;k++){
        int16_t ur=re[i+k+len/2],ui=im[i+k+len/2];
        re[i+k+len/2]=re[i+k]-ur;
        im[i+k+len/2]=im[i+k]-ui;
        re[i+k]+=ur;im[i+k]+=ui;}
  uint16_t pk=0;*pb=0;
  for(uint8_t i=1;i<n/2;i++){
    int16_t ra=abs(re[i]),ia=abs(im[i]);
    uint16_t mg=(ra>ia)?(ra+(uint16_t)(0.4f*ia)):(ia+(uint16_t)(0.4f*ra));
    if(mg>pk){pk=mg;*pb=i;}}
  return pk;
}
